sql:
SELECT DISTINCT researchers.researcher_name
FROM researchers
INNER JOIN model_configurations ON researchers.researcher_id = model_configurations.researcher_id;

external_knowledge:
- "gardeners" refers to researchers;
- "sown the seeds of knowledge" indicates sharing configurations;
- "first treasure chest" refers to the configuration with ID 0;
- "fellow explorers" indicates other researchers through the `shared_with` list.

sql:
SELECT (
  SELECT CAST(COUNT(DISTINCT n.researcher_id) AS FLOAT) * 100 / (SELECT COUNT(DISTINCT researcher_id) FROM researchers)
  FROM researchers r
  JOIN notifications n ON r.researcher_id = n.researcher_id
  WHERE n.notification_type = 'new result' AND n.model_version_id = 1
) AS percentage;

